"use client"

import React from "react"
import { motion } from "framer-motion"
import { useRouter } from "next/navigation"
import TagCard from "@/components/TagCard"
import { tagData } from "./tagData"

const containerVariants = {
  hidden: {},
  visible: {
    transition: {
      staggerChildren: 0.1,
    },
  },
}

const cardVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0 },
}

export default function TagsPage() {
  const router = useRouter()

  return (
    <main className="bg-slate-900 text-white min-h-screen pt-8 pb-16">
      <section className="max-w-7xl mx-auto px-4 md:px-8">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.4 }}
        >
          <h1 className="text-3xl md:text-4xl font-bold mb-2">Explore by Topics</h1>
          <p className="text-slate-400 mb-6 text-sm md:text-base">
            Click on a topic to discover relevant posts.
          </p>
        </motion.div>

        {/* Tag Cards Grid */}
        <motion.div
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6"
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          {tagData.map((tag) => (
            <motion.div key={tag.title} variants={cardVariants}>
              <TagCard
                title={tag.title}
                image={tag.image}
                description={tag.description}
                onClick={() => {
                  router.push(`/posts?tag=${encodeURIComponent(tag.title)}`)
                }}
              />
            </motion.div>
          ))}
        </motion.div>
      </section>
    </main>
  )
}
